// // Custom hook to use cart context
// export const useCart = () => useContext(CartContext);
import React, {
  createContext,
  useContext,
  useState,
  useEffect,
  useCallback,
  useMemo,
} from "react";

import { getHeaders } from "../../utils";
import { api } from "../../../lib/api";

const CartContext = createContext();

export const CartProvider = ({ children }) => {
  const [cart, setCart] = useState({ items: [] });
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);

  const [totals, setTotals] = useState({
    originalTotal: 0,
    discountTotal: 0,
    finalTotal: 0,
  });

  // CALCULATE TOTALS
  const calculateTotals = useCallback((items = []) => {
    let original = 0;
    let discount = 0;

    items.forEach((item) => {
      const price = item.product?.price || 0;
      const discountPercentage = item.product?.discountPercentage || 0;
      const quantity = item.quantity || 1;

      original += price * quantity;
      discount += (price * discountPercentage * quantity) / 100;
    });

    setTotals({
      originalTotal: original,
      discountTotal: discount,
      finalTotal: original - discount,
    });
  }, []);

  // FETCH CART
  const fetchCart = useCallback(async () => {
    try {
      setLoading(true);

      const res = await api.get("/cart/view/", {
        headers: getHeaders(),
      });

      const data = res.data || { items: [] };
      setCart(data);
      calculateTotals(data.items || []);
    } catch (err) {
      console.error(err);
      setError("Failed to load cart");
    } finally {
      setLoading(false);
    }
  }, [calculateTotals]);

  useEffect(() => {
    fetchCart();
  }, [fetchCart]);

  // ADD TO CART (OPTIMISTIC)
  const addToCart = async (product) => {
    setCart((prev) => ({
      ...prev,
      items: [...prev.items, { product, quantity: 1 }],
    }));

    try {
      await api.post(
        "/cart/add/",
        {
          product_id: product.id,
          quantity: 1,
        },
        { headers: getHeaders() }
      );

      await fetchCart();
    } catch (err) {
      console.error(err);
      fetchCart();
    }
  };

  // REMOVE
  const removeFromCart = async (productId) => {
    setCart((prev) => ({
      ...prev,
      items: prev.items.filter((i) => i.product.id !== productId),
    }));

    try {
      await api.delete(`/cart/remove/${productId}/`, {
        headers: getHeaders(),
      });
    } catch {
      fetchCart();
    }
  };

  // UPDATE QUANTITY
  const updateCartQuantity = async (productId, quantity) => {
    setCart((prev) => ({
      ...prev,
      items: prev.items.map((i) =>
        i.product.id === productId ? { ...i, quantity } : i
      ),
    }));

    try {
      await api.put(
        `/cart/update/${productId}/`,
        { quantity },
        { headers: getHeaders() }
      );
    } catch {
      fetchCart();
    }
  };

  const value = useMemo(
    () => ({
      cart,
      loading,
      error,
      totals,
      fetchCart,
      addToCart,
      removeFromCart,
      updateCartQuantity,
    }),
    [cart, loading, error, totals, fetchCart]
  );

  return <CartContext.Provider value={value}>{children}</CartContext.Provider>;
};

export const useCart = () => useContext(CartContext);
